import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, SalaryRecord, AuditLog, GPSLog } from './types';
import { mockUsers, mockAttendance, mockLeaves, mockSalaries, mockAuditLogs } from './mockData';
import { isOfficeIp, isWithinOfficeRadius } from './utils';

interface HRMContextType {
  currentUser: User | null;
  users: User[];
  attendance: AttendanceRecord[];
  leaves: LeaveRequest[];
  salaries: SalaryRecord[];
  auditLogs: AuditLog[];
  gpsLogs: GPSLog[];
  login: (email: string, role: UserRole) => Promise<boolean>;
  logout: () => void;
  checkIn: (lat: number, lng: number, accuracy: number, ip: string) => Promise<{ success: boolean; message: string }>;
  checkOut: (lat: number, lng: number, accuracy: number, ip: string) => Promise<{ success: boolean; message: string }>;
  applyLeave: (leave: Omit<LeaveRequest, 'id' | 'status' | 'userName'>) => void;
  updateLeave: (id: string, status: LeaveRequest['status']) => void;
  addAuditLog: (action: string, details: string, severity: AuditLog['severity']) => void;
  addGPSLog: (log: GPSLog) => void;
}

const HRMContext = createContext<HRMContextType | undefined>(undefined);

export const HRMProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(mockUsers);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>(mockAttendance);
  const [leaves, setLeaves] = useState<LeaveRequest[]>(mockLeaves);
  const [salaries, setSalaries] = useState<SalaryRecord[]>(mockSalaries);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>(mockAuditLogs);
  const [gpsLogs, setGpsLogs] = useState<GPSLog[]>([]);

  const addAuditLog = useCallback((action: string, details: string, severity: AuditLog['severity']) => {
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      userId: currentUser?.id || 'system',
      userName: currentUser?.name || 'System',
      action,
      details,
      severity
    };
    setAuditLogs(prev => [newLog, ...prev].slice(0, 1000));
  }, [currentUser]);

  const login = async (email: string, role: UserRole): Promise<boolean> => {
    const user = users.find(u => u.email === email && u.role === role);
    if (user) {
      setCurrentUser(user);
      addAuditLog('USER_LOGIN', `User logged in from simulated device`, 'LOW');
      return true;
    }
    addAuditLog('FAILED_LOGIN', `Failed login attempt for ${email}`, 'MEDIUM');
    return false;
  };

  const logout = () => {
    addAuditLog('USER_LOGOUT', 'User logged out', 'LOW');
    setCurrentUser(null);
  };

  const checkIn = async (lat: number, lng: number, accuracy: number, ip: string) => {
    if (!currentUser) return { success: false, message: 'Not authenticated' };

    const inOfficeRange = isWithinOfficeRadius(lat, lng);
    const inOfficeSubnet = isOfficeIp(ip);

    if (!inOfficeSubnet) {
      addAuditLog('ATTENDANCE_DENIED', `Check-in rejected: Outside office network (${ip})`, 'MEDIUM');
      return { success: false, message: 'Please connect to the office WiFi to check in.' };
    }

    if (!inOfficeRange) {
      addAuditLog('ATTENDANCE_DENIED', `Check-in rejected: Outside geo-fence (${lat.toFixed(4)}, ${lng.toFixed(4)})`, 'MEDIUM');
      return { success: false, message: 'You are too far from the office building.' };
    }

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      timestamp: new Date().toISOString(),
      type: 'CHECK_IN',
      location: { lat, lng, accuracy },
      ipAddress: ip,
      status: 'SUCCESS'
    };

    setAttendance(prev => [...prev, newRecord]);
    addAuditLog('ATTENDANCE_SUCCESS', 'User checked in successfully', 'LOW');
    return { success: true, message: 'Checked in successfully!' };
  };

  const checkOut = async (lat: number, lng: number, accuracy: number, ip: string) => {
    // Similar logic for checkout
    if (!currentUser) return { success: false, message: 'Not authenticated' };

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      timestamp: new Date().toISOString(),
      type: 'CHECK_OUT',
      location: { lat, lng, accuracy },
      ipAddress: ip,
      status: 'SUCCESS'
    };

    setAttendance(prev => [...prev, newRecord]);
    addAuditLog('ATTENDANCE_SUCCESS', 'User checked out successfully', 'LOW');
    return { success: true, message: 'Checked out successfully!' };
  };

  const applyLeave = (leave: Omit<LeaveRequest, 'id' | 'status' | 'userName'>) => {
    const newLeave: LeaveRequest = {
      ...leave,
      id: Math.random().toString(36).substr(2, 9),
      status: LeaveStatus.PENDING,
      userName: currentUser?.name || 'Unknown'
    };
    setLeaves(prev => [...prev, newLeave]);
    addAuditLog('LEAVE_REQUEST', `Leave applied: ${leave.type}`, 'LOW');
  };

  const updateLeave = (id: string, status: LeaveStatus) => {
    setLeaves(prev => prev.map(l => l.id === id ? { ...l, status } : l));
    addAuditLog('LEAVE_UPDATE', `Leave ${id} status updated to ${status}`, 'MEDIUM');
  };

  const addGPSLog = useCallback((log: GPSLog) => {
    setGpsLogs(prev => [...prev, log].slice(-1000));
  }, []);

  return (
    <HRMContext.Provider value={{
      currentUser, users, attendance, leaves, salaries, auditLogs, gpsLogs,
      login, logout, checkIn, checkOut, applyLeave, updateLeave, addAuditLog, addGPSLog
    }}>
      {children}
    </HRMContext.Provider>
  );
};

export const useHRM = () => {
  const context = useContext(HRMContext);
  if (context === undefined) {
    throw new Error('useHRM must be used within an HRMProvider');
  }
  return context;
};

import { GoogleGenAI, Type } from "@google/genai";
import { AuditLog } from './types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeSecurityLogs = async (logs: AuditLog[]) => {
  try {
    const logSummary = logs.map(l => `[${l.timestamp}] ${l.severity} - ${l.action}: ${l.details}`).join('\n');

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `As a cybersecurity expert, analyze the following HRM system audit logs for suspicious patterns like brute-force attacks, unauthorized IP access, or VPN usage. Return a JSON report.

      Logs:
      ${logSummary}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            riskLevel: { type: Type.STRING, description: 'Low, Medium, or High' },
            summary: { type: Type.STRING },
            anomalies: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  timestamp: { type: Type.STRING },
                  description: { type: Type.STRING },
                  threatType: { type: Type.STRING }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ['riskLevel', 'summary', 'anomalies', 'recommendations']
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Security Analysis Error:", error);
    return null;
  }
};

