import React, { useState, useEffect } from 'react';
import { useHRM } from '../store';
import { MapPin, Wifi, ShieldCheck, Clock, Send, AlertTriangle } from 'lucide-react';
import { formatDate } from '../utils';

const EmployeePortal: React.FC = () => {
  const { currentUser, checkIn, checkOut, attendance, applyLeave, addGPSLog } = useHRM();
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [mockIp, setMockIp] = useState('192.168.1.52');
  const [mockLoc, setMockLoc] = useState({ lat: 40.7128, lng: -74.0060 });

  // Simulate background tracking
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      addGPSLog({
        userId: currentUser.id,
        lat: mockLoc.lat + (Math.random() - 0.5) * 0.001,
        lng: mockLoc.lng + (Math.random() - 0.5) * 0.001,
        timestamp: new Date().toISOString(),
        accuracy: 10
      });
    }, 10000); // Track every 10 seconds for demo (normally 5 mins)
    return () => clearInterval(interval);
  }, [currentUser, mockLoc, addGPSLog]);

  const handleAttendance = async (type: 'IN' | 'OUT') => {
    setLoading(true);
    setFeedback(null);
    try {
      // Simulate real geo-loc delay
      await new Promise(r => setTimeout(r, 1000));
      const res = type === 'IN' 
        ? await checkIn(mockLoc.lat, mockLoc.lng, 10, mockIp)
        : await checkOut(mockLoc.lat, mockLoc.lng, 10, mockIp);

      setFeedback({ type: res.success ? 'success' : 'error', message: res.message });
    } catch (err) {
      setFeedback({ type: 'error', message: 'Failed to communicate with secure server' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-md mx-auto space-y-6">
      <div className="bg-indigo-600 text-white rounded-2xl p-6 shadow-xl relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-indigo-100 text-sm font-medium">Welcome back,</p>
          <h2 className="text-2xl font-bold">{currentUser?.name}</h2>
          <p className="text-indigo-200 text-sm mt-1">{currentUser?.department} Team</p>
        </div>
        <div className="absolute top-0 right-0 p-4 opacity-20">
          <ShieldCheck size={100} />
        </div>
      </div>

      {/* Attendance Widget */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
        <div className="flex items-center justify-between mb-6">
          <h3 className="font-bold text-gray-700">Daily Attendance</h3>
          <div className="flex gap-2">
            <span className={`px-2 py-1 rounded-full text-[10px] flex items-center gap-1 ${mockIp.startsWith('192.168.1') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
              <Wifi size={10} /> {mockIp.startsWith('192.168.1') ? 'Office WiFi' : 'Guest Network'}
