        </div>

        {feedback && (
          <div className={`mb-4 p-4 rounded-xl text-sm flex items-center gap-2 ${feedback.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
            {feedback.type === 'success' ? <ShieldCheck size={18} /> : <AlertTriangle size={18} />}
            {feedback.message}
