import React, { useEffect, useRef } from 'react';
import { useHRM } from '../store';
import L from 'leaflet';

const LiveTracking: React.FC = () => {
  const { gpsLogs, users } = useHRM();
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});

  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current) return;

    mapRef.current = L.map(mapContainerRef.current).setView([40.7128, -74.0060], 13);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap contributors'
    }).addTo(mapRef.current);

    // Office boundary circle
    L.circle([40.7128, -74.0060], {
      color: '#4f46e5',
      fillColor: '#4f46e5',
      fillOpacity: 0.1,
      radius: 500
    }).addTo(mapRef.current).bindPopup('NYC Head Office (Geo-fence Boundary)');

    return () => {
      mapRef.current?.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!mapRef.current) return;

    // Group logs by user to show only latest position
    const latestPositions: { [key: string]: any } = {};
    gpsLogs.forEach(log => {
      latestPositions[log.userId] = log;
    });

    Object.values(latestPositions).forEach(pos => {
      const user = users.find(u => u.id === pos.userId);
      const name = user?.name || 'Unknown';

      if (markersRef.current[pos.userId]) {
        markersRef.current[pos.userId].setLatLng([pos.lat, pos.lng]);
      } else {
        const marker = L.marker([pos.lat, pos.lng])
          .addTo(mapRef.current!)
          .bindPopup(`<b>${name}</b><br/>Last Active: ${new Date(pos.timestamp).toLocaleTimeString()}`);
        markersRef.current[pos.userId] = marker;
      }
    });
  }, [gpsLogs, users]);

  return (
    <div className="h-full flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Field Workforce Map</h2>
          <p className="text-gray-500 text-sm">Real-time GPS tracking for security and efficiency.</p>
        </div>
        <div className="flex gap-4">
          <div className="flex items-center gap-2">
            <span className="w-3 h-3 rounded-full bg-green-500 animate-pulse"></span>
            <span className="text-sm font-medium">Live Stream Active</span>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden relative">
        <div ref={mapContainerRef} className="h-full w-full z-0" />

        {/* Overlay Legend */}
        <div className="absolute bottom-4 left-4 z-10 bg-white/90 backdrop-blur-md p-3 rounded-lg shadow-lg border border-gray-200 pointer-events-none">
          <h4 className="text-xs font-bold text-gray-800 uppercase mb-2">Legend</h4>
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-xs">
              <span className="w-2 h-2 rounded-full bg-blue-500"></span>
              <span>Head Office</span>
            </div>
            <div className="flex items-center gap-2 text-xs">
              <span className="w-2 h-2 rounded-full bg-indigo-600"></span>
              <span>Geo-fence Area</span>
            </div>
            <div className="flex items-center gap-2 text-xs">
              <span className="w-2 h-2 bg-black h-1 w-1"></span>
              <span>Active Employee</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LiveTracking;

