                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="Official Email"
                  className="w-full pl-14 pr-5 py-4 bg-slate-50/80 border-2 border-transparent rounded-2xl text-sm focus:bg-white focus:ring-4 focus:ring-red-50 transition-all duration-300 focus:border-red-500/20 placeholder:text-slate-300"
                />
              </div>
              <div className="relative group">
                <KeyRound className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 w-5 h-5 group-focus-within:text-red-500 transition-colors duration-300" />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Security Password"
                  className="w-full pl-14 pr-5 py-4 bg-slate-50/80 border-2 border-transparent rounded-2xl text-sm focus:bg-white focus:ring-4 focus:ring-red-50 transition-all duration-300 focus:border-red-500/20 placeholder:text-slate-300"
                />
              </div>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 text-xs font-bold py-3.5 px-5 rounded-2xl text-center flex items-center justify-center gap-2 border border-red-100 animate-[shake_0.4s_ease-in-out]">
                <ShieldAlert size={14} />
                {error}
              </div>
            )}

            <button
              type="submit"
              className="w-full py-4.5 bg-slate-950 hover:bg-red-600 text-white rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-2xl shadow-slate-200 transition-all duration-300 active:scale-[0.98] hover:-translate-y-1"
            >
              Secure Login
            </button>
          </form>

          <div className="pt-8 border-t border-slate-100 text-center">
            <p className="text-[10px] text-slate-400 font-medium leading-relaxed">
              Exord Enterprise Authentication Protocol v4.2<br/>
              <span className="text-red-600/60 mt-1 block">Internal Access Restricted</span>
            </p>
          </div>
        </div>
      </div>
    );
  }

  const renderView = () => {
    switch (activeView) {
      case 'dashboard': return <AdminDashboard />;
      case 'portal': return <EmployeePortal />;
      case 'tracking': return <LiveTracking />;
      case 'security': return <SecurityLogs />;
      case 'attendance': 
        return currentUser.role === UserRole.ADMIN ? <AdminDashboard /> : <EmployeePortal />;
      default: return (
        <div className="flex flex-col items-center justify-center h-[60vh] text-center space-y-4">
          <Globe className="w-16 h-16 text-slate-200 animate-pulse" />
          <div className="p-8 max-w-sm mx-auto text-slate-400 font-medium italic">
            Module under cryptographic review. Authorized internal users only.
          </div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-inter">
      {/* Sidebar - Responsive */}
      <Sidebar 
        activeView={activeView} 
        setActiveView={setActiveView} 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
      />

      {/* Overlay for mobile sidebar */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-[2px] z-40 md:hidden transition-opacity duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <main className={`flex-1 flex flex-col min-h-screen transition-all duration-300 ${isSidebarOpen ? 'md:ml-64' : 'md:ml-64'}`}>
        {/* Responsive Header */}
        <header className="sticky top-0 z-30 flex items-center justify-between px-4 sm:px-8 py-5 bg-white/80 backdrop-blur-md border-b border-slate-100">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2.5 bg-slate-50 text-slate-600 rounded-xl md:hidden hover:bg-slate-100 transition-colors"
            >
              <Menu size={20} />
            </button>
            <div className="hidden sm:block">
              <h1 className="text-lg font-black text-slate-900 capitalize tracking-tight flex items-center gap-2">
                {activeView.replace('-', ' ')}
                <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-pulse shadow-[0_0_8px_rgba(220,38,38,0.5)]"></span>
              </h1>
              <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest">Protocol 7 - Secure Channel</p>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-6">
            <div className="hidden lg:flex items-center bg-slate-100/80 rounded-2xl px-4 py-2 text-slate-400 group focus-within:bg-white focus-within:ring-2 focus-within:ring-red-100 transition-all">
              <Search size={16} className="mr-2 group-focus-within:text-red-500" />
              <input type="text" placeholder="Search system..." className="bg-transparent border-none text-xs font-medium focus:ring-0 placeholder:text-slate-400 w-40 xl:w-64" />
            </div>

            <button className="p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all relative">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-600 rounded-full border-2 border-white"></span>
            </button>

            <div className="flex items-center gap-3 sm:pl-6 sm:border-l border-slate-100">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-slate-900 leading-none">{currentUser.name}</p>
                <p className="text-[9px] text-red-600 font-bold uppercase tracking-widest mt-1">{currentUser.department}</p>
              </div>
              <div className="w-10 h-10 rounded-2xl bg-slate-950 text-white flex items-center justify-center font-black border-2 border-red-600/20 shadow-xl transition-transform hover:scale-105">
                {currentUser.name.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        {/* Content with view transition */}
        <div className="flex-1 p-4 sm:p-8 animate-[fadeIn_0.5s_ease-out]">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
