import React, { useState, useEffect } from 'react';
import { useHRM } from '../store';
import { MapPin, Wifi, ShieldCheck, Clock, Send, AlertTriangle, Globe, ChevronRight, Fingerprint, MapPinned } from 'lucide-react';
import { formatDate } from '../utils';

const EmployeePortal: React.FC = () => {
  const { currentUser, checkIn, checkOut, attendance, applyLeave, addGPSLog } = useHRM();
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [mockIp, setMockIp] = useState('192.168.1.52');
  const [mockLoc, setMockLoc] = useState({ lat: 40.7128, lng: -74.0060 });

  // Simulate background tracking
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      addGPSLog({
        userId: currentUser.id,
        lat: mockLoc.lat + (Math.random() - 0.5) * 0.001,
        lng: mockLoc.lng + (Math.random() - 0.5) * 0.001,
        timestamp: new Date().toISOString(),
        accuracy: 10
      });
    }, 10000);
    return () => clearInterval(interval);
  }, [currentUser, mockLoc, addGPSLog]);

  const handleAttendance = async (type: 'IN' | 'OUT') => {
    setLoading(true);
    setFeedback(null);
    try {
      await new Promise(r => setTimeout(r, 1200)); // Simulate slightly longer "biometric" process
      const res = type === 'IN' 
        ? await checkIn(mockLoc.lat, mockLoc.lng, 10, mockIp)
        : await checkOut(mockLoc.lat, mockLoc.lng, 10, mockIp);

      setFeedback({ type: res.success ? 'success' : 'error', message: res.message });

      // Auto-clear feedback after 5 seconds
      setTimeout(() => setFeedback(null), 5000);
    } catch (err) {
      setFeedback({ type: 'error', message: 'Secure tunnel handshake failed. Please retry.' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.5s_ease-out]">
      {/* User Header Profile */}
      <div className="bg-slate-950 text-white rounded-[2.5rem] p-8 sm:p-10 shadow-2xl relative overflow-hidden border border-slate-800">
        <div className="absolute top-0 right-0 w-64 h-64 bg-red-600/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="absolute bottom-0 left-0 w-32 h-32 bg-indigo-600/10 rounded-full -ml-10 -mb-10 blur-2xl"></div>

        <div className="relative z-10 flex flex-col sm:flex-row sm:items-center justify-between gap-6">
          <div className="flex items-center gap-5">
            <div className="w-20 h-20 rounded-3xl bg-red-600 flex items-center justify-center font-black text-3xl shadow-xl shadow-red-900/40 relative">
              {currentUser?.name.charAt(0)}
              <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-emerald-500 rounded-full border-4 border-slate-950 flex items-center justify-center">
                <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
              </div>
            </div>
            <div>
              <p className="text-red-500 text-[11px] font-black uppercase tracking-[0.25em] mb-1">Secure ID: {currentUser?.id}</p>
              <h2 className="text-3xl font-black tracking-tight">{currentUser?.name}</h2>
              <div className="flex items-center gap-2 mt-2">
                <span className="px-2 py-0.5 bg-slate-800 text-slate-300 rounded-md text-[10px] font-black uppercase tracking-widest">{currentUser?.department}</span>
                <span className="text-slate-500 text-xs font-bold flex items-center gap-1"><MapPin size={12} /> HQ Sector 4</span>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-end">
            <div className="bg-slate-900/80 backdrop-blur-md rounded-2xl p-4 border border-slate-800 text-right min-w-[140px]">
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mb-1">Local IP State</p>
              <p className={`text-sm font-black flex items-center justify-end gap-2 ${mockIp.startsWith('192.168.1') ? 'text-emerald-400' : 'text-red-400'}`}>
                {mockIp.startsWith('192.168.1') ? <Wifi size={14} /> : <AlertTriangle size={14} />}
                {mockIp}
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Primary Actions */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-8 sm:p-10">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-10">
          <div>
            <h3 className="font-black text-slate-900 uppercase tracking-widest text-[11px] mb-1">Operations Control</h3>
            <p className="text-sm text-slate-400 font-medium">Biometric clocking & geo-verification</p>
          </div>
          <div className="flex gap-2">
            <div className="px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-100 text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-2">
               <Fingerprint size={12} className="text-red-600" /> Bio-Active
            </div>
            <div className="px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-100 text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-2">
               <MapPinned size={12} className="text-red-600" /> GPS Locked
            </div>
          </div>
        </div>

        {feedback && (
          <div className={`mb-8 p-5 rounded-[1.5rem] text-xs font-bold flex items-center gap-4 animate-[slideDown_0.3s_ease-out] border ${
            feedback.type === 'success' 
            ? 'bg-emerald-50 text-emerald-800 border-emerald-100 shadow-sm' 
            : 'bg-rose-50 text-rose-800 border-rose-100 shadow-sm'
          }`}>
            <div className={`p-2 rounded-xl ${feedback.type === 'success' ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
              {feedback.type === 'success' ? <ShieldCheck size={20} /> : <AlertTriangle size={20} />}
            </div>
            <p className="leading-relaxed">{feedback.message}</p>
          </div>
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <button
            onClick={() => handleAttendance('IN')}
            disabled={loading}
            className="flex flex-col items-center justify-center gap-5 p-10 rounded-[2rem] bg-red-50 hover:bg-red-100/80 text-red-700 transition-all duration-300 border border-transparent active:scale-[0.97] disabled:opacity-50 group shadow-sm hover:shadow-xl hover:shadow-red-200/40 relative overflow-hidden"
          >
            <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform duration-500">
               <Clock size={32} className="group-hover:rotate-12 transition-transform" />
            </div>
            <div className="text-center">
              <span className="font-black text-xs uppercase tracking-[0.25em] block mb-1">Clock In</span>
              <span className="text-[10px] font-bold text-red-400 uppercase tracking-widest">Start Daily Shift</span>
            </div>
            {loading && <div className="absolute inset-0 bg-red-600/5 flex items-center justify-center backdrop-blur-[1px] animate-pulse"></div>}
          </button>

          <button
            onClick={() => handleAttendance('OUT')}
            disabled={loading}
            className="flex flex-col items-center justify-center gap-5 p-10 rounded-[2rem] bg-slate-900 hover:bg-slate-950 text-white transition-all duration-300 border border-transparent active:scale-[0.97] disabled:opacity-50 group shadow-sm hover:shadow-xl hover:shadow-slate-200/40"
          >
            <div className="w-16 h-16 bg-slate-800 rounded-3xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform duration-500">
               <Send size={32} className="rotate-45 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
            </div>
            <div className="text-center">
              <span className="font-black text-xs uppercase tracking-[0.25em] block mb-1">Clock Out</span>
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">End Session Duty</span>
            </div>
          </button>
        </div>

        {/* Simulator Tools Card - Improved UI */}
        <div className="mt-10 p-6 rounded-3xl bg-slate-50 border border-slate-100">
          <div className="flex items-center gap-3 mb-5">
            <Activity size={16} className="text-red-500" />
            <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest">System Simulator Console</p>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {[
              { label: 'Exord HQ Net', active: mockIp === '192.168.1.52', onClick: () => setMockIp('192.168.1.52') },
              { label: 'Public Net', active: mockIp === '10.0.0.1', onClick: () => setMockIp('10.0.0.1') },
              { label: 'On-Site Geo', active: mockLoc.lat === 40.7128, onClick: () => setMockLoc({ lat: 40.7128, lng: -74.0060 }) },
              { label: 'Remote Geo', active: mockLoc.lat === 41, onClick: () => setMockLoc({ lat: 41, lng: -75 }) },
            ].map((tool, i) => (
              <button 
                key={i}
                onClick={tool.onClick} 
                className={`text-[9px] font-black uppercase py-2.5 rounded-xl transition-all border-2 ${
                  tool.active 
                  ? 'bg-slate-950 text-white border-slate-950 shadow-lg shadow-slate-200' 
                  : 'bg-white text-slate-400 border-white hover:border-slate-200'
                }`}
              >
                {tool.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Records & History */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-8 sm:p-10">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h3 className="font-black text-slate-900 uppercase tracking-widest text-[11px] mb-1">Sequence Archive</h3>
            <p className="text-sm text-slate-400 font-medium">Recent shift authentication history</p>
          </div>
          <button className="p-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <Activity size={18} />
          </button>
        </div>

        <div className="space-y-4">
          {attendance.filter(a => a.userId === currentUser?.id).slice(-4).reverse().map((record, i) => (
            <div 
              key={record.id} 
              className="flex items-center justify-between p-5 bg-slate-50/50 rounded-2xl border border-slate-100 hover:bg-white hover:shadow-xl hover:shadow-slate-200/50 hover:border-red-100 transition-all duration-300 group cursor-default"
              style={{ animationDelay: `${i * 100}ms` }}
            >
              <div className="flex items-center gap-5">
                <div className={`p-3 rounded-2xl transition-transform duration-500 group-hover:scale-110 shadow-sm ${
                  record.type === 'CHECK_IN' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'
                }`}>
                  <Clock size={18} />
                </div>
                <div>
                  <p className="text-[11px] font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    {record.type === 'CHECK_IN' ? 'Duty Check-In' : 'Duty Check-Out'}
                    <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                    <span className="text-[10px] text-slate-400 font-bold lowercase tracking-normal">{record.ipAddress}</span>
                  </p>
                  <p className="text-xs text-slate-500 font-medium mt-0.5">{formatDate(record.timestamp)}</p>
                </div>
              </div>
              <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-xl border border-slate-100 shadow-sm">
                <ShieldCheck size={14} className="text-emerald-500" />
                <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Verified</span>
                <ChevronRight size={14} className="text-slate-300 group-hover:translate-x-0.5 transition-transform" />
              </div>
            </div>
          ))}

          {attendance.filter(a => a.userId === currentUser?.id).length === 0 && (
            <div className="py-12 text-center text-slate-400 italic text-sm border-2 border-dashed border-slate-100 rounded-3xl">
              No authenticated records found for this sector.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

