        <div className="flex-1 p-4 sm:p-10 max-w-[1600px] mx-auto w-full overflow-y-auto custom-scrollbar">
          {activeView === 'dashboard' && <AdminDashboard />}
          {activeView === 'employees' && <WorkforceView />}
          {activeView === 'portal' && <EmployeePortal />}
          {activeView === 'tracking' && <LiveTracking />}
          {activeView === 'security' && <SecurityLogs />}
          {activeView === 'attendance' && (currentUser.role === UserRole.ADMIN ? <AdminDashboard /> : <EmployeePortal />)}
        </div>
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <HRMProvider>
      <MainApp />
    </HRMProvider>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { useHRM } from '../store';
import L from 'leaflet';
import { Map as MapIcon, Users, Target, Crosshair, MapPinned, Activity } from 'lucide-react';

const LiveTracking: React.FC = () => {
  const { gpsLogs, users } = useHRM();
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});
  const [selectedUser, setSelectedUser] = useState<string | null>(null);

  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current) return;

    mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([40.7128, -74.0060], 13);
    L.tileLayer('https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      attribution: '© CartoDB'
    }).addTo(mapRef.current);

    L.circle([40.7128, -74.0060], {
      color: '#E31E24',
      fillColor: '#E31E24',
      fillOpacity: 0.15,
      radius: 500,
      weight: 1
    }).addTo(mapRef.current).bindPopup('Exord HQ (Primary Geofence)');

    return () => {
      mapRef.current?.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!mapRef.current) return;

    const latestPositions: { [key: string]: any } = {};
    gpsLogs.forEach(log => {
      latestPositions[log.userId] = log;
    });

    Object.values(latestPositions).forEach(pos => {
      const user = users.find(u => u.id === pos.userId);
      if (!user) return;

      if (markersRef.current[pos.userId]) {
        markersRef.current[pos.userId].setLatLng([pos.lat, pos.lng]);
      } else {
        const marker = L.marker([pos.lat, pos.lng], {
          icon: L.divIcon({
            className: 'custom-div-icon',
            html: `<div class="w-8 h-8 bg-[#E31E24] rounded-full border-4 border-white dark:border-slate-900 shadow-xl flex items-center justify-center text-white text-[10px] font-black">${user.name.charAt(0)}</div>`,
            iconSize: [32, 32],
            iconAnchor: [16, 16]
          })
        })
          .addTo(mapRef.current!)
          .bindPopup(`<b>${user.name}</b><br/>${user.department}`);
        markersRef.current[pos.userId] = marker;
      }

      if (selectedUser === pos.userId) {
         mapRef.current?.panTo([pos.lat, pos.lng], { animate: true });
      }
    });
  }, [gpsLogs, users, selectedUser]);

  const activeUserIds = Array.from(new Set(gpsLogs.map(l => l.userId)));

  return (
    <div className="h-full flex flex-col lg:flex-row gap-6 animate-[fadeIn_0.5s_ease-out]">
      <div className="w-full lg:w-80 flex flex-col gap-4">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border-2 border-slate-200 dark:border-slate-800 shadow-sm">
          <div className="flex items-center gap-3 mb-6">
            <Users size={20} className="text-[#E31E24]" />
            <h3 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white">Active Telemetry</h3>
          </div>
          <div className="space-y-2">
            {activeUserIds.length === 0 && <p className="text-xs text-slate-400 italic">No active surveillance nodes detected.</p>}
            {activeUserIds.map(uid => {
               const user = users.find(u => u.id === uid);
               return (
                 <button 
                  key={uid}
                  onClick={() => setSelectedUser(uid)}
                  className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all border-2 ${selectedUser === uid ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-slate-900 dark:border-white' : 'bg-slate-50 dark:bg-slate-800 border-transparent text-slate-600 dark:text-slate-300'}`}
                 >
                    <div className="w-8 h-8 rounded-lg bg-[#E31E24] text-white flex items-center justify-center font-black text-xs">{user?.name.charAt(0)}</div>
                    <div className="text-left">
                       <p className="text-xs font-black truncate max-w-[120px]">{user?.name}</p>
                       <p className="text-[10px] opacity-60 font-bold uppercase tracking-widest">{uid}</p>
                    </div>
                    <Activity size={12} className="ml-auto text-emerald-500 animate-pulse" />
                 </button>
               );
            })}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border-2 border-slate-200 dark:border-slate-800 hidden lg:block">
           <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Network Protocols</h4>
           <div className="space-y-3">
              <div className="flex items-center gap-3 text-[11px] font-bold text-slate-600 dark:text-slate-400">
                 <div className="w-2 h-2 rounded-full bg-[#E31E24]"></div> Exord HQ Perimeter
              </div>
              <div className="flex items-center gap-3 text-[11px] font-bold text-slate-600 dark:text-slate-400">
                 <div className="w-2 h-2 rounded-full bg-emerald-500"></div> Authorized Asset
              </div>
           </div>
        </div>
      </div>

      <div className="flex-1 bg-white dark:bg-slate-900 rounded-[3rem] border-2 border-slate-300 dark:border-slate-800 overflow-hidden relative shadow-2xl min-h-[400px]">
        <div ref={mapContainerRef} className="h-full w-full z-0" />
        <div className="absolute top-6 right-6 z-10 flex flex-col gap-2">
           <button onClick={() => mapRef.current?.setView([40.7128, -74.0060], 15)} className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-xl border border-slate-200 dark:border-slate-700 hover:scale-110 transition-transform">
              <Target size={20} className="text-[#E31E24]" />
           </button>
        </div>
      </div>
    </div>
  );
};

export default LiveTracking;

